const input = $json.body ?? $json;
const requestId = String(input.request_id ?? '').trim();
const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

return [{
  json: {
    ok: uuidPattern.test(requestId),
    request_id: requestId,
    error: uuidPattern.test(requestId) ? null : {
      code: 'INVALID_REQUEST_ID',
      message: 'request_id يجب أن يكون UUID صالحًا.'
    }
  }
}];

const rows = Array.isArray($json) ? $json : ($json.data ?? []);
const row = Array.isArray(rows) ? rows[0] : null;

if (!row) {
  return [{ json: { ok: false, http_status: 404, error: {
    code: 'REQUEST_NOT_FOUND',
    message: 'لم يتم العثور على طلب الحملة.'
  }}}];
}

if (!['draft','pending_resolution','resolution_failed'].includes(row.status)) {
  return [{ json: { ok: false, http_status: 409, error: {
    code: 'INVALID_REQUEST_STATUS',
    message: `لا يمكن حل الطلب عندما تكون حالته ${row.status}.`
  }, request: row }}];
}

return [{
  json: {
    ok: true,
    http_status: 200,
    request: row,
    source_platform: row.source_platform,
    source_post_url: row.source_post_url
  }
}];

const base = $('Validate Loaded Request').first().json;
const response = $json;
const mediaId = response.media_id ?? response.id ?? null;
const shortcode = (() => {
  const m = base.source_post_url.match(/instagram\.com\/(?:p|reel|reels|tv)\/([^/?#]+)/i);
  return m ? m[1] : null;
})();

if (!mediaId) {
  return [{
    json: {
      ok: false,
      http_status: 422,
      request: base.request,
      resolution: {
        resolver_status: 'failed',
        resolver_method: 'instagram_oembed',
        source_shortcode: shortcode,
        error_code: 'INSTAGRAM_MEDIA_ID_NOT_RETURNED',
        error_message: response?.error?.message ?? response?.error?.error?.message ??
          'Meta oEmbed لم يُرجع Instagram media_id. تحقق من صلاحية الرابط والتوكن ووضع التطبيق.'
      }
    }
  }];
}

return [{
  json: {
    ok: true,
    http_status: 200,
    request: base.request,
    resolution: {
      resolver_status: 'resolved',
      resolver_method: 'instagram_oembed',
      source_shortcode: shortcode,
      source_post_id: String(mediaId),
      instagram_media_id: String(mediaId),
      object_story_id: null
    }
  }
}];

const base = $('Validate Loaded Request').first().json;
const url = base.source_post_url;
const PAGE_ID = '1196152526914949';

function match(pattern) {
  const m = url.match(pattern);
  return m ? m[1] : null;
}

const composite = match(/story_fbid=(\d+).*?[?&]id=(\d+)/i);
let postId =
  match(/\/posts\/(\d+)/i) ||
  match(/\/videos\/(\d+)/i) ||
  match(/\/reel\/(\d+)/i) ||
  match(/[?&]story_fbid=(\d+)/i) ||
  match(/[?&]fbid=(\d+)/i);

let objectStoryId = null;
let method = null;

if (composite) {
  objectStoryId = `${PAGE_ID}_${composite}`;
  method = 'facebook_query_story_fbid';
} else if (postId) {
  objectStoryId = postId.includes('_') ? postId : `${PAGE_ID}_${postId}`;
  method = 'facebook_canonical_url_parser';
}

if (!postId) {
  return [{
    json: {
      ok: false,
      http_status: 422,
      request: base.request,
      resolution: {
        resolver_status: 'failed',
        resolver_method: 'facebook_canonical_url_parser',
        error_code: 'FACEBOOK_POST_ID_NOT_FOUND',
        error_message: 'تعذر استخراج رقم المنشور من رابط Facebook. استخدم الرابط الأصلي الذي يحتوي /posts/ أو /videos/ أو /reel/.'
      }
    }
  }];
}

return [{
  json: {
    ok: true,
    http_status: 200,
    request: base.request,
    resolution: {
      resolver_status: 'resolved',
      resolver_method: method,
      source_post_id: String(postId),
      instagram_media_id: null,
      object_story_id: objectStoryId
    }
  }
}];

const item = $json;
const previous = item.request?.request_payload ?? {};
const resolution = item.resolution ?? {};
const now = new Date().toISOString();

return [{
  json: {
    ok: item.ok,
    http_status: item.http_status,
    request_id: item.request?.id,
    patch: {
      status: item.ok ? 'draft' : 'resolution_failed',
      error_code: item.ok ? null : (resolution.error_code ?? 'RESOLUTION_FAILED'),
      error_message: item.ok ? null : (resolution.error_message ?? 'تعذر حل المنشور.'),
      request_payload: {
        ...previous,
        ...resolution,
        resolved_at: item.ok ? now : null,
        resolution_attempted_at: now
      }
    },
    resolution
  }
}];

const row = Array.isArray($json) ? $json[0] : $json;
const payload = row?.request_payload ?? {};
const ok = payload.resolver_status === 'resolved';

return [{
  json: {
    ok,
    http_status: ok ? 200 : 422,
    request_id: row?.id ?? null,
    status: row?.status ?? null,
    source_platform: row?.source_platform ?? null,
    source_post_url: row?.source_post_url ?? null,
    resolver_status: payload.resolver_status ?? null,
    resolver_method: payload.resolver_method ?? null,
    source_post_id: payload.source_post_id ?? null,
    object_story_id: payload.object_story_id ?? null,
    instagram_media_id: payload.instagram_media_id ?? null,
    error_code: row?.error_code ?? null,
    error_message: row?.error_message ?? null,
    message: ok
      ? 'تم حل معرّف المنشور الموجود وحفظه في طلب الحملة.'
      : 'تم حفظ فشل عملية الحل داخل طلب الحملة.'
  }
}];

const source = $json;
return [{
  json: {
    ok: false,
    http_status: source.http_status ?? 400,
    error_code: source.error?.code ?? 'RESOLVER_REQUEST_FAILED',
    error_message: source.error?.message ?? 'تعذر تنفيذ طلب حل المنشور.'
  }
}];
